PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
SELECT ?aid ?fn WHERE { { SELECT ?aid (COUNT(?m) AS ?c) WHERE { ?m a :Movies ; p:LeadActressId ?laid . ?a a :Actress ; p:id ?aid . FILTER(STR(?laid)=STR(?aid)) } GROUP BY ?aid } ?a2 a :Actress ; p:id ?aid ; p:name ?fn . { SELECT (MAX(?c2) AS ?mx) WHERE { SELECT ?aid2 (COUNT(?m2) AS ?c2) WHERE { ?m2 a :Movies ; p:LeadActressId ?l2 . ?ax a :Actress ; p:id ?aid2 . FILTER(STR(?l2)=STR(?aid2)) } GROUP BY ?aid2 } } FILTER(?c = ?mx) }

